<template>
  <div class="flex h-screen bg-gray-100">
    <!-- Sidebar -->
    <div 
      :class="[
        'bg-white shadow-lg transition-all duration-300 ease-in-out',
        isCollapsed ? 'w-16' : 'w-64'
      ]"
    >
      <!-- Plant Header -->
      <div class="p-4 border-b border-gray-200">
        <div class="flex items-center space-x-3">
          <div class="w-8 h-8 bg-blue-500 rounded-lg flex items-center justify-center flex-shrink-0">
            <span class="text-white text-sm font-bold">🏭</span>
          </div>
          <div v-if="!isCollapsed" class="flex-1 min-w-0">
            <h2 class="text-sm font-semibold text-gray-900 truncate">Mahadevpura</h2>
            <p class="text-xs text-gray-500 truncate">Primary Production</p>
          </div>
        </div>
      </div>

      <!-- Navigation Menu -->
      <nav class="mt-4 px-2">
        <ul class="space-y-1">
          <li v-for="item in navigationItems" :key="item.id">
            <router-link
              :to="item.route"
              :class="[
                'group flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors duration-200',
                isActive(item.route) 
                  ? 'bg-blue-100 text-blue-700 border-r-2 border-blue-500' 
                  : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
              ]"
              @click="setActiveItem(item.id)"
            >
              <span class="text-lg mr-3 flex-shrink-0">{{ item.icon }}</span>
              <span v-if="!isCollapsed" class="truncate">{{ item.name }}</span>
            </router-link>
          </li>
        </ul>
      </nav>

      <!-- Collapse Toggle -->
      <div class="absolute bottom-4 left-4">
        <button
          @click="toggleCollapse"
          class="p-2 rounded-md bg-gray-100 hover:bg-gray-200 transition-colors duration-200"
        >
          <svg 
            :class="[
              'w-4 h-4 text-gray-600 transition-transform duration-200',
              isCollapsed ? 'rotate-180' : ''
            ]"
            fill="none" 
            stroke="currentColor" 
            viewBox="0 0 24 24"
          >
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M15 19l-7-7 7-7" />
          </svg>
        </button>
      </div>
    </div>

    <!-- Main Content Area -->
    <div class="flex-1 flex flex-col overflow-hidden">
      <!-- Top Bar -->
      <div class="bg-white shadow-sm border-b border-gray-200 px-6 py-4">
        <div class="flex items-center justify-between">
          <div class="flex items-center space-x-4">
            <button
              @click="toggleCollapse"
              class="p-2 rounded-md hover:bg-gray-100 transition-colors duration-200 lg:hidden"
            >
              <svg class="w-5 h-5 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M4 6h16M4 12h16M4 18h16" />
              </svg>
            </button>
            <h1 class="text-xl font-semibold text-gray-900">{{ currentPageTitle }}</h1>
          </div>
          
          <!-- User Dropdown -->
          <UserDropdown 
            :plant="plantConfig"
            @logout="handleLogout"
          />
        </div>
      </div>

      <!-- Page Content -->
      <main class="flex-1 overflow-auto bg-gray-50">
        <router-view />
      </main>
    </div>
  </div>
</template>

<script setup>
import { ref, computed, onMounted, watch } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { useSessionStore } from '@/core/stores/session.js'
import UserDropdown from '@/app/components/UserDropdown.vue'

const route = useRoute()
const router = useRouter()
const sessionStore = useSessionStore()

// State
const isCollapsed = ref(false)
const activeItem = ref('dashboard')

// Plant configuration
const plantConfig = {
  name: 'Mahadevpura Plant',
  location: 'Primary Production Facility',
  plantId: 'mahadevpura'
}

// Navigation items for Mahadevpura (removed profile)
const navigationItems = ref([
  {
    id: 'dashboard',
    name: 'Dashboard',
    icon: '📊',
    route: '/plant/mahadevpura/dashboard'
  },
  {
    id: 'grn',
    name: 'GRN',
    icon: '📦',
    route: '/plant/mahadevpura/grn'
  },
  {
    id: 'production-order',
    name: 'Production Order',
    icon: '🏭',
    route: '/plant/mahadevpura/production-order'
  },
  {
    id: 'quality',
    name: 'Quality',
    icon: '✅',
    route: '/plant/mahadevpura/quality'
  },
  {
    id: 'inventory-transfer',
    name: 'Inventory Transfer',
    icon: '🔄',
    route: '/plant/mahadevpura/inventory-transfer'
  }
])

// Computed
const currentUser = computed(() => sessionStore.user)

const currentPageTitle = computed(() => {
  const currentItem = navigationItems.value.find(item => item.route === route.path)
  return currentItem ? currentItem.name : 'Mahadevpura Plant'
})

// Methods
const toggleCollapse = () => {
  isCollapsed.value = !isCollapsed.value
  saveNavigationState()
}

const setActiveItem = (itemId) => {
  activeItem.value = itemId
  saveNavigationState()
}

const isActive = (routePath) => {
  return route.path === routePath
}

const handleLogout = async () => {
  try {
    await sessionStore.logout()
    router.push('/plant-selection')
  } catch (error) {
    console.error('Logout error:', error)
    // Force logout even if API call fails
    sessionStore.clearSession()
    router.push('/plant-selection')
  }
}

const saveNavigationState = () => {
  const state = {
    isCollapsed: isCollapsed.value,
    activeItem: activeItem.value,
    plant: 'mahadevpura'
  }
  localStorage.setItem('mahadevpura-nav-state', JSON.stringify(state))
}

const loadNavigationState = () => {
  try {
    const saved = localStorage.getItem('mahadevpura-nav-state')
    if (saved) {
      const state = JSON.parse(saved)
      if (state.plant === 'mahadevpura') {
        isCollapsed.value = state.isCollapsed || false
        activeItem.value = state.activeItem || 'dashboard'
      }
    }
  } catch (error) {
    console.error('Error loading navigation state:', error)
  }
}

// Watch for route changes
watch(route, (newRoute) => {
  const currentItem = navigationItems.value.find(item => item.route === newRoute.path)
  if (currentItem) {
    activeItem.value = currentItem.id
    saveNavigationState()
  }
}, { immediate: true })

// Initialize
onMounted(() => {
  loadNavigationState()
})
</script>
